var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 건국기념전당, 타나베린\\n레아 슈나이더","JPN":"グロニア建国記念館、タナベリン\\nレア・シュナイダー","ENG":"Gronia’s National Foundation Hall, Tanaberin\\nLeah Schneider","TWN":"格羅尼亞 建國紀念堂，達那貝林\\n蕾亞·修奈德"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"후우……. 오늘 청소할 구역은 이걸로 끝인가?","JPN":"ふう……今日掃除するエリアはこれで終わりかな？","ENG":"Whew... Is today’s cleanup finally over?","TWN":"呼……今天要打掃的地方應該就這些吧？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"건국절까지 끝내려면 지금 인원들만 가지곤 어림도 없겠는데.","JPN":"この人数で建国記念日まで終わらせるのは無理だよ。","ENG":"If we want to finish by National Foundation Day, it’ll be difficult with these few people.","TWN":"要在國慶之前處理完畢的話，光靠目前的人力應該有困難吧？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"하하. 걱정 마요, 레아.","JPN":"はは。心配する必要はないですよ、レア。","ENG":"Ha ha. Don’t worry, Leah.","TWN":"哈哈，你儘管放心，蕾亞。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"건물이 크긴 하지만 관리가 필요한 곳은 절반도 안 돼요. 사용하지 않는 구역이 많거든요.","JPN":"建物は大きいですが、管理が必要な場所は半分もありません。使っていないエリアが多いですから。","ENG":"Although the building is large, only half of it requires maintenance. Many areas are unused.","TWN":"這棟建築物雖然很大，但需要管理的地方不多，因為有很多區域都沒在使用。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"특히 대정화전쟁 시기에 증축한 곳들은 미로나 다름없어요. 지하실에서 실종된 사람 이야기는 유명하잖아요?","JPN":"特に大浄化戦争の時期に増築した部分は迷路同然です。地下室で失踪した人の話は有名でしょう？","ENG":"In particular, areas built during the Grand Purification War are like a maze. The story of a man going missing in the basement is quite famous, right?","TWN":"尤其是在大淨化戰爭時期擴建的地方，根本就像迷宮一樣，那個地下室失蹤奇案不是很有名嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"이런, 불평하는 걸 들켜 버렸네요. 실장님.","JPN":"おっと、愚痴がバレてしまいましたね。室長。","ENG":"Oh, I’m sorry if I’ve been complaining a little too much, Manager.","TWN":"哎呀，被室長發現，我其實是在抱怨呢～"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"괜찮아요. 담당 구역이 다 끝났으면 이만 가 보셔도 됩니다.","JPN":"大丈夫です。担当エリアが終わったのなら帰っても構いません。","ENG":"No problem. You may go now if your area is all finished.","TWN":"沒事的，你負責的區域處理完畢後，就可以先離開沒問題。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"근무 시간이 아직 남았는데, 그래도 될까요?","JPN":"まだ勤務時間が残ってますが、大丈夫ですか？","ENG":"It’s a bit earlier than when I normally get off, is it really okay?","TWN":"但現在還是上班時間，這樣沒關係嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"그럼요. 어차피 몇 분 있으면 공연 연습 때문에 드나들기도 힘들 겁니다.","JPN":"ええ。どうせ数分後には公演の練習があるので、出入りしづらくなるでしょう。","ENG":"Of course. In a few more minutes, it will be difficult to get in and out due to the rehearsal.","TWN":"當然沒關係，反正再過幾分鐘後，就要開始彩排演出，到時候進出會很不方便。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"여기 오늘치 일당이에요. 조금 넉넉하게 챙겨 드렸습니다.","JPN":"さあ、今日の日給です。少し多めに入れておきました。","ENG":"Here are your wages for the day. This should be more than enough.","TWN":"這是今天的工資，我有多給你一點。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"아. 그러고 보니 친구 분이 어머님을 모시고 오셨더군요.","JPN":"あ。そういえばお友達がお母さんと一緒にいらしてましたよ。","ENG":"Ah. Come to think of it, a friend of yours brought your mother.","TWN":"話說回來，你的朋友好像帶著媽媽來找你。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"안젤라가요?","JPN":"アンジェラがですか？","ENG":"You mean Angela?","TWN":"你說安潔拉嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"네. 관심 있으면 2층 좌석에서 좀 구경하다 가세요. 출입구를 열어 둘 테니까요.","JPN":"はい。気になるなら、2階の席でちょっと見ていきなさい。出入口を開けておきますから。","ENG":"Correct. If you’re interested, take the seats on the second floor, I’ll leave the door open.","TWN":"對，有興趣的話，你們可以上2樓的觀眾席參觀一下再走，出口我會幫你開著。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"배려는 감사하지만 괜찮아요. 먼저 퇴근하겠습니다, 실장님.","JPN":"お気遣いはありがたいですが、大丈夫です。お先に失礼します、室長。","ENG":"Thank you for thinking of me, but I’m okay. I’ll be going home, Manager.","TWN":"謝謝室長費心，但沒關係，我先下班了。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니, 춥지는 않으세요?","JPN":"おばさん、寒くないですか？","ENG":"Madam, aren’t you cold?","TWN":"伯母，你會冷嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……. 그럼……. 바람을 쐬니 참 좋아요…….","JPN":"ううん……大丈夫……風がとても気持ちいいですね……","ENG":"Huh?... Well... It is so nice to get some fresh air...","TWN":"喔……還好……風很舒服……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아 일이 끝나려면 조금 더 있어야 할 거예요.","JPN":"レアの仕事が終わるまでもうちょっとかかりますよ。","ENG":"We have to wait a little longer for Leah to get off of work.","TWN":"蕾亞應該還要等一下才會下班。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"기다리는 동안 전당 안에 들어가서 구경해 보실래요?","JPN":"待ってる間、記念館の中に入って見てみますか？","ENG":"Would you like to go inside the hall and look around while we wait?","TWN":"伯母要不要進去一邊欣賞表演，一邊等她下班？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아니……. 들어가기 싫어요……. 사람들이 무슨 눈으로 볼지 무서워요…….","JPN":"いや……入りたくないです……みんなにどんな目で見られるか怖い……","ENG":"No... I don’t want to go inside... Too many people with their frightening eyes...","TWN":"不要……我不要進去……他們會用很可怕的眼神看我，我會怕……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니…….","JPN":"おばさん……","ENG":"Madam...","TWN":"伯母……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"……안젤라, 엄마. 여기 있었구나.","JPN":"……アンジェラ、お母さん。ここにいたんだね。","ENG":"...Angela, and Mom. There you are.","TWN":"……安潔拉、媽！你們在這裡喔！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"오오……. 레아. 일은 잘 끝났니?","JPN":"おお……レア。仕事は終わったのかい？","ENG":"Ooh... Leah. How was work, sweetie?","TWN":"喔……蕾亞，你下班啦？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니가 답답해하셔서 밖으로 모시고 나왔어. 마침 너도 일이 끝날 시간이라.","JPN":"おばさんが息苦しそうだったから外に出てみたの。ちょうどレアの仕事も終わる頃だしね。","ENG":"Madam was feeling a little cooped up so I took her outside. Happens to be that you also finish work around this time.","TWN":"伯母在家閒得發慌，我想說帶她出來走走，剛好也快到你下班的時間。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"오는 동안 별일 없었어? 며칠 전에도 용병들 보고 발작 일으키셨잖아.","JPN":"ここに来る間は大丈夫だった？　この前にも傭兵を見て発作を起こしたでしょ？","ENG":"How was the trip here? She saw the mercenaries a few days ago and had a seizure, right?","TWN":"你們來的時候沒發生什麼事吧？前幾天不是才因為看到傭兵，所以又發作起來嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"응. 조금 무서워하시긴 했지만……. 집 안에만 계시면 상태가 더 안 좋아지시니까.","JPN":"うん。ちょっと怖そうにされたけど……家の中にばかりいると状態が悪化するからね。","ENG":"Yeah, she was a little scared, but... Her condition worsens when she only stays inside.","TWN":"嗯，伯母是有點緊張不安……但一直待在家裡，狀態反而更不好。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"그래도 그렇지. 엄마는 네가 집에서 연주 연습만 해도 좋아할 텐데.","JPN":"それもそうだけど。お母さんはアンジェラが家で演奏の練習をするだけでも喜ぶのに。","ENG":"But still, Mom would love it even if you just practiced at home.","TWN":"你說的也對，只要你在家練習演奏的話，我媽應該就會很開心吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"후훗. 내 연주가 아주머니 성에 찰 리 없잖아.","JPN":"ふふっ。私の演奏におばさんが満足するわけないでしょ？","ENG":"Ha. My playing wouldn’t live up to Madam’s standards.","TWN":"呵呵，我在伯母面前是小巫見大巫吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그렇죠, 아주머니?","JPN":"そうですよね、おばさん？","ENG":"Isn’t that right, Madam?","TWN":"對吧，伯母？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"바깥 공기를 마시니……. 머리가 아주 맑아졌어요.","JPN":"外の空気を吸ったら……とても頭がすっきりしました。","ENG":"Breathing in the fresh air... Oh everything feels so clear.","TWN":"外面空氣真好……覺得神清氣爽的。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"하여간……. 엄마는 나보다 안젤라랑 죽이 더 잘 맞네.","JPN":"もう……お母さんったら、私よりアンジェラと息が合うのね。","ENG":"Anyways... You get along better with Mom than I do.","TWN":"我看……我媽跟你更合得來吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그럼. 그만큼 정성껏 보살펴 드리고 있으니까.","JPN":"もちろん。それくらい誠心誠意お世話してるんですもの。","ENG":"Well yeah. I’m the one who takes care of her all the time.","TWN":"那當然！我那麼用心在照顧她。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"……그래. 네가 없었으면 벌써 예전에 큰일 났을 거야.","JPN":"……うん。アンジェラがいなかったらもうとっくに大変なことになってる。","ENG":"...Yeah. If it weren’t for you, I wouldn’t have known what to do.","TWN":"……真的，要不是有你，可能早就出大事了。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"일당도 받았는데, 가는 길에 잠깐 암시장 들를래?","JPN":"日給ももらったし、帰り道にちょっと闇市場に寄ってかない？","ENG":"I just got paid today, want to stop by the black market on the way?","TWN":"我拿到薪水了，回去的時候要不要順便去黑市逛逛？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"우후후. 버터가 남아 있다니 오늘은 운이 좋네.","JPN":"うふふ。バターが残ってるなんて、今日はついてるわね。","ENG":"Ha ha. They have butter! It’s my lucky day.","TWN":"呵呵呵，今天運氣真好，奶油竟然還沒賣光！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"안젤라, 내가 말을 꺼냈다지만 한 번에 너무 많이 샀어.","JPN":"アンジェラ、私が誘ったんだけどいっぺんに買いすぎ。","ENG":"Angela, I know I’m the one who mentioned it, but we bought too much.","TWN":"安潔拉，雖然是我說要來逛的，但你會不會買太多啦？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"식재료 값이 또 언제 오를지 모르는걸. 쌀 때 많이 사 둬야 돼.","JPN":"またいつ値上がりするかわからないもの。安い時にたくさん買っておかないと。","ENG":"We don’t know when food prices will go up again! We’ve got to buy a lot and save it.","TWN":"食材不知道什麼時候又要漲價，當然要趁現在多買一點囤貨囉！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그리고 오늘은 아주머니가 좋아하시는 팬케이크도 굽기로 했잖아?","JPN":"それに、今日はおばさんの好きなパンケーキも焼くんでしょ？","ENG":"We’re going to make Madam’s favorite pancakes today, aren’t we?","TWN":"而且我今天已經跟伯母說好，要做她喜歡的鬆餅給她吃～"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"너무해. 엄마랑 둘이서 마음대로 정했으면서.","JPN":"ひどい。お母さんと二人で決めたことじゃない。","ENG":"Pooh. You and mom just decided it without telling me.","TWN":"好過分，你們竟然自己偷偷說好！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"엄마는……. 레아가 만들어 주는 음식이면 뭐든 좋았단다.","JPN":"お母さんは……レアが作ってくれる食事なら何でもよかったのよ。","ENG":"I... like everything Leah makes for me.","TWN":"媽媽呢……只要是蕾亞做的東西，我全都喜歡。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그 작은 손으로 타 준 차를 마시고 있으면 피아노를 쳐 주는데, 어찌나 실력이 좋던지.","JPN":"その小さな手で淹れてくれたお茶を飲んでると、ピアノを弾いてくれて、それがもうとても上手だった。","ENG":"Such beautiful, small delicate hands. Perfect for playing piano and drinking tea.","TWN":"媽媽只要喝著用你那雙小手泡的茶，琴就彈得特別好呢～"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그래도 그 예쁜 손을 더럽히지 않아서 다행이야……. 요즘 사람들은 손에 피를 아무렇지도 않게 묻혀서…….","JPN":"でもその綺麗な手を汚さなくてよかった……最近の人たちは平気で手を血まみれにするから……","ENG":"I’m so glad those pretty little hands haven’t gotten dirty yet. These days, so many people have blood on their hands...","TWN":"不過幸好你那雙美麗的手沒有弄髒……最近的人殺人跟吃飯一樣自然，都不當一回事……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그게, 그게 얼마나 끔찍한 짓인지도 모르고…….","JPN":"それが、それがどれほどむごい事なのかも知らずに……","ENG":"It’s, It’s such a terrible thing...","TWN":"這有多可怕啊……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"나쁜 생각은 몸에 안 좋아요, 엄마. 병이 나으려면 좋은 생각만 해야죠.","JPN":"悪い考えは体によくないよ、お母さん。病気を治すにはいいことだけ考えなきゃね。","ENG":"Such horrible thoughts are bad for your health, Mom. You need to think a little more positively to get better.","TWN":"媽媽，想這些不好的事對你的身體不好，要多想些正面的事，病才好得快。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"엄마?","JPN":"お母さん？","ENG":"Mom?","TWN":"媽？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"병이요……?","JPN":"病気……？","ENG":"Bad for health…?","TWN":"病……？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아가씨는……. 누구신데 날 엄마라고 불러요?","JPN":"お嬢さんは……誰？　なんで私をお母さんって呼ぶんですか？","ENG":"Hey... Why are you calling me Mom?","TWN":"小姐……你是誰？為什麼喊我媽媽呢？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"사람 잘못 보셨어요. 저랑 한두 살 차이 날 것 같은데.","JPN":"人違いです。私とあまり歳の差もなさそうなのに。","ENG":"I’m so sorry, I think you have the wrong person. There can’t be an age difference between us.","TWN":"你認錯人了，我跟你的年紀應該差不多吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그런데 레아는…….","JPN":"ところでレアは……","ENG":"But Leah...","TWN":"蕾亞呢……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"우리 레아는 어디로 갔어요……? 아까까지 여기 있었는데……?","JPN":"レアはどこに行ったんですか……？　さっきまでここにいたのに……？","ENG":"Where’d my Leah go...? She was just here a moment ago...?","TWN":"我們蕾亞跑哪去了……？她剛剛不是還在這裡嗎……？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아……? 레아……!!","JPN":"レア……？　レア……！！","ENG":"Leah...? Leah...!!","TWN":"蕾亞……？蕾亞……！！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"……진정하세요, 어머님.","JPN":"……落ち着いてください、お母さん。","ENG":"...Calm down, Madam.","TWN":"……伯母，你先冷靜點。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"레아는 집에서 엄마를 기다리고 있어요. 금방 모셔다 드릴게요.","JPN":"レアは家でお母さんを待ってますよ。すぐにお連れします。","ENG":"Leah is waiting for you at home. You’ll see her in a minute.","TWN":"蕾亞在家裡等你，我們現在就送你回去。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그, 그래요? 그렇죠? 우리 레아는 어린 나이에 영리하니까, 네?","JPN":"そ、そう？　そうですよね？　レアは小さいけど賢いんだから、ね？","ENG":"R-really? Is that so? My Leah is so smart for her age, isn’t she?","TWN":"喔…是嗎？我就知道，我們蕾亞雖然還小，但她可是很聰明伶俐的，你說是不是？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아아, 감사합니다. 젊은 분들이 친절도 하시지…….","JPN":"ああ、ありがとうございます。お若いのにご親切に……","ENG":"Ah, thank you. Young people these days are so kind.","TWN":"對了，謝謝你們，真是親切的年輕人……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아, 힘들면 내가 할게. 잠깐 밖에서 쉬다가 들어와.","JPN":"レア、辛かったら私がやるわ。少し外で休んでから来て。","ENG":"Leah, if it’s too hard for you, I’ll do it. Take a break outside for a minute and come back.","TWN":"蕾亞，你累的話，就讓我來吧。你在外面休息一下再進來"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"아니. 매번 너한테만 맡기기도 미안해.","JPN":"ううん。いつも任せっきりじゃ悪いよ。","ENG":"No, it’s okay. I’m sorry you have to do this every time.","TWN":"沒關係，怎麼好意思每次都麻煩你呢。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"이번 공연도 내가 출장 갔을 때 엄마 돌봐 주느라 참가 못한 거고.","JPN":"今度の公演も私が出張の間、お母さんの面倒を見たせいで参加できなかったし。","ENG":"You couldn’t perform in the concert because I was away on a business trip... You had to stay home and take care of Mom.","TWN":"這次也是因為我要出差，你要幫我照顧媽媽才沒辦法參與演出的。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그렇지 않아, 레아. 괜한 죄책감 갖지 않아도 돼.","JPN":"そんなことないわ、レア。変に罪悪感を感じなくて大丈夫よ。","ENG":"Hey, don’t be like that, Leah. You don’t need to feel guilty.","TWN":"你別這麼想，蕾亞，你不需要對我感到抱歉。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"사실대로 말할 뿐이야, 안젤라.","JPN":"本当のことを言っただけだよ、アンジェラ。","ENG":"It’s simply the truth, Angela.","TWN":"我只是照實說而已，安潔拉。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"가자. 집에서 한동안 조용히 계시면 다시 정신이 돌아오시겠지.","JPN":"行こう。しばらく家で静かに過ごしたらまた正気を取り戻すよ。","ENG":"Come on. Let’s go home where it’s nice and quiet. Mom will be herself again.","TWN":"走吧，回到家後，她休息一下應該就會恢復正常。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이 나라는, 이유도 잊은 채 서로 죽고 죽이길 거듭하고 있었다.","JPN":"この国は、理由も忘れたまま、くり返しお互いを殺し合っていた。","ENG":"People in this country have been killing each other for so long nobody even remembers the reason why.","TWN":"在這個國家，人們不斷盲目地互相殘殺。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 사람들은 필사적으로 하루하루를 살아가려 했고.","JPN":"だけど人々は必死に毎日を生きようとしていて。","ENG":"People are desperately clinging to their lives everyday.","TWN":"卻又拼命想要在每一天活下去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"사람을 오래 기다리게 하는군. 슈나이더.","JPN":"人を待たせすぎだな。シュナイダー。","ENG":"You like to make people wait, Schneider.","TWN":"我等你好久了，修奈德。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"잠시 얘기를 나눴으면 하는데, 괜찮겠나?","JPN":"少し話をしたいのだが、いいか？","ENG":"I’d like to have a little chat. It’ll only take a moment. Will that be alright?","TWN":"方便借一步說話嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"……국장님?","JPN":"……局長？","ENG":"...Chief?","TWN":"……部長？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"파레마 건은…… 정리가 끝났다고 들었는데요.","JPN":"パレマの件は……すでに片付いたと聞きましたけど。","ENG":"About the failure in Parema... I heard everything has been cleaned up.","TWN":"波雷馬的事……據我所知不是已經結束了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"파레마는 그랬지.","JPN":"パレマはそうだったな。","ENG":"In Parema, yes.","TWN":"波雷馬的事是結束了，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……이번엔 그보다 더 심각한 사안이야.","JPN":"……今度はそれよりもっと深刻だ。","ENG":"...This is a much more serious matter.","TWN":"……但還有更嚴重的事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"언제부터인가, 서로 손에 피를 묻히는 걸 당연하다고 여기게 되었다.","JPN":"いつからか、お互い手を血に染めることを当たり前と考えるようになった。","ENG":"At some point, it becomes so normal to get our hands dirty.","TWN":"曾幾何時，彼此的手染上鮮血變得如此習以為常。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};